```cpp
// fcmp oeq (select (fcmp ord X, 0.0), X, 0.0), C --> fcmp oeq X, C
// This pattern checks if X is ordered (not NaN), and if so uses X, otherwise 0.0.
// When comparing with a non-zero constant C using oeq, this is equivalent to
// just comparing X with C, because:
// - If X is NaN: select returns 0.0, (0.0 == C) is false for non-zero C
// - If X is ordered: select returns X, (X == C) is the same
// Note: This is only valid when C != 0.0
if (Pred == FCmpInst::FCMP_OEQ && !match(RHSC, m_AnyZeroFP())) {
  Value *CondX, *SelectVal;
  Constant *CondC, *FalseVal;
  FCmpInst::Predicate CondPred;
  // Match: select (fcmp ord CondX, CondC), SelectVal, FalseVal
  // where CondC and FalseVal are zeros, and SelectVal == CondX
  if (match(LHSI, m_Select(m_FCmp(CondPred, m_Value(CondX), m_Constant(CondC)),
                           m_Value(SelectVal), m_Constant(FalseVal))) &&
      CondPred == FCmpInst::FCMP_ORD &&
      match(CondC, m_AnyZeroFP()) &&
      match(FalseVal, m_AnyZeroFP()) &&
      SelectVal == CondX)
    return new FCmpInst(Pred, SelectVal, RHSC, "", &I);
  // Also handle the case where select operands are swapped
  if (match(LHSI, m_Select(m_FCmp(CondPred, m_Value(CondX), m_Constant(CondC)),
                           m_Constant(FalseVal), m_Value(SelectVal))) &&
      CondPred == FCmpInst::FCMP_ORD &&
      match(CondC, m_AnyZeroFP()) &&
      match(FalseVal, m_AnyZeroFP()) &&
      SelectVal == CondX)
